from flask import Flask, session, request, jsonify
import redis
import functools
import time
import hashlib

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

@app.before_request
def check_session():
    if 'user_id' not in session:
        session['user_id'] = None

@app.route('/login', methods=['POST'])
def login():
    user_id = request.json.get('user_id')
    if user_id:
        session['user_id'] = user_id
        # Store session in Redis
        session_key = f"session:{session.sid}"
        redis_client.setex(session_key, 3600, user_id)  # 1 hour expiry
        return jsonify({'status': 'success'})
    return jsonify({'status': 'failed'}), 401

@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'status': 'logged_out'})

def cache_result(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"cache:{func.__name__}:{hashlib.md5(str(args).encode()).hexdigest()}"
            
            # Try to get from cache
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return jsonify({'cached': True, 'result': cached_result})
            
            # Execute function and cache result
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, str(result))
            return jsonify({'cached': False, 'result': result})
        return wrapper
    return decorator

@app.route('/expensive-query')
@cache_result(expiration=600)
def expensive_query():
    # Simulate expensive database query
    time.sleep(2)
    return {'data': 'expensive_query_result', 'timestamp': time.time()}

@app.route('/user/<user_id>')
@cache_result(expiration=300)
def get_user(user_id):
    # Simulate database query
    time.sleep(1)
    return {'user_id': user_id, 'name': f'User {user_id}'}

if __name__ == '__main__':
    app.run(debug=False)